extern "C" fn vfstrace_open(p_vfs: *mut Sqlite3Vfs, z_name: *const i8,
    p_file: *mut Sqlite3File, flags: i32, p_out_flags: *mut i32) -> i32 {
    let mut rc: i32 = 0;
    let p: *mut VfstraceFile = p_file as *mut VfstraceFile;
    let p_info: *mut VfstraceInfo =
        unsafe { (*p_vfs).p_app_data } as *mut VfstraceInfo;
    let p_root: *mut Sqlite3Vfs = unsafe { (*p_info).p_root_vfs };
    unsafe { (*p).p_info = p_info };
    unsafe {
        (*p).z_f_name =
            if !(z_name).is_null() {
                file_tail(z_name)
            } else { c"<temp>".as_ptr() as *mut i8 as *const i8 }
    };
    unsafe {
        (*p).p_real =
            unsafe { &raw mut *p.offset(1 as isize) } as *mut Sqlite3File
    };
    rc =
        unsafe {
            (unsafe {
                    (*p_root).x_open.unwrap()
                })(p_root, z_name, unsafe { (*p).p_real }, flags, p_out_flags)
        };
    vfstrace_on_off(unsafe { &mut *p_info }, 65536 as u32);
    unsafe {
        vfstrace_printf(unsafe { &*p_info },
            c"%s.xOpen(%s,flags=0x%x)".as_ptr() as *mut i8 as *const i8,
            unsafe { (*p_info).z_vfs_name }, unsafe { (*p).z_f_name }, flags)
    };
    if !(unsafe { (*unsafe { (*p).p_real }).p_methods }).is_null() {
        let p_new: *mut Sqlite3IoMethods =
            unsafe {
                    sqlite3_malloc64(core::mem::size_of::<Sqlite3IoMethods>() as
                            Sqlite3Uint64)
                } as *mut Sqlite3IoMethods;
        let p_sub: *const Sqlite3IoMethods =
            unsafe { (*unsafe { (*p).p_real }).p_methods };
        unsafe {
            memset(p_new as *mut (), 0,
                core::mem::size_of::<Sqlite3IoMethods>() as u64)
        };
        unsafe { (*p_new).i_version = unsafe { (*p_sub).i_version } as i32 };
        unsafe { (*p_new).x_close = Some(vfstrace_close) };
        unsafe { (*p_new).x_read = Some(vfstrace_read) };
        unsafe { (*p_new).x_write = Some(vfstrace_write) };
        unsafe { (*p_new).x_truncate = Some(vfstrace_truncate) };
        unsafe { (*p_new).x_sync = Some(vfstrace_sync) };
        unsafe { (*p_new).x_file_size = Some(vfstrace_file_size) };
        unsafe { (*p_new).x_lock = Some(vfstrace_lock) };
        unsafe { (*p_new).x_unlock = Some(vfstrace_unlock) };
        unsafe {
            (*p_new).x_check_reserved_lock =
                Some(vfstrace_check_reserved_lock)
        };
        unsafe { (*p_new).x_file_control = Some(vfstrace_file_control) };
        unsafe { (*p_new).x_sector_size = Some(vfstrace_sector_size) };
        unsafe {
            (*p_new).x_device_characteristics =
                Some(vfstrace_device_characteristics)
        };
        if unsafe { (*p_new).i_version } >= 2 {
            unsafe {
                (*p_new).x_shm_map =
                    if unsafe { (*p_sub).x_shm_map.is_some() } {
                        Some(vfstrace_shm_map)
                    } else { None }
            };
            unsafe {
                (*p_new).x_shm_lock =
                    if unsafe { (*p_sub).x_shm_lock.is_some() } {
                        Some(vfstrace_shm_lock)
                    } else { None }
            };
            unsafe {
                (*p_new).x_shm_barrier =
                    if unsafe { (*p_sub).x_shm_barrier.is_some() } {
                        Some(vfstrace_shm_barrier)
                    } else { None }
            };
            unsafe {
                (*p_new).x_shm_unmap =
                    if unsafe { (*p_sub).x_shm_unmap.is_some() } {
                        Some(vfstrace_shm_unmap)
                    } else { None }
            };
        }
        if unsafe { (*p_new).i_version } >= 3 {
            unsafe {
                (*p_new).x_fetch =
                    if unsafe { (*p_sub).x_fetch.is_some() } {
                        Some(vfstrace_fetch)
                    } else { None }
            };
            unsafe {
                (*p_new).x_unfetch =
                    if unsafe { (*p_sub).x_unfetch.is_some() } {
                        Some(vfstrace_unfetch)
                    } else { None }
            };
        }
        unsafe { (*p_file).p_methods = p_new as *const Sqlite3IoMethods };
    }
    vfstrace_print_errcode(p_info, c" -> %s".as_ptr() as *mut i8 as *const i8,
        rc);
    if !(p_out_flags).is_null() {
        unsafe {
            vfstrace_printf(unsafe { &*p_info },
                c", outFlags=0x%x\n".as_ptr() as *mut i8 as *const i8,
                unsafe { *p_out_flags })
        };
    } else {
        unsafe {
            vfstrace_printf(unsafe { &*p_info },
                c"\n".as_ptr() as *mut i8 as *const i8)
        };
    }
    return rc;
}

