extern "C" fn run_schema_dump_query(p: *mut ShellState, z_query_1: *const i8)
    -> i32 {
    let mut rc: i32 = 0;
    let mut z_err: *mut i8 = core::ptr::null_mut();
    rc =
        unsafe {
            sqlite3_exec(unsafe { (*p).db }, z_query_1, Some(dump_callback),
                p as *mut (), &mut z_err)
        };
    if rc == 11 {
        let mut z_q2: *mut i8 = core::ptr::null_mut();
        let len: i32 = strlen30(z_query_1);
        cli_puts(c"/****** CORRUPTION ERROR *******/\n".as_ptr() as *mut i8 as
                *const i8, unsafe { (*p).out });
        if !(z_err).is_null() {
            unsafe {
                cli_printf(unsafe { (*p).out },
                    c"/****** %s ******/\n".as_ptr() as *mut i8 as *const i8,
                    z_err)
            };
            unsafe { sqlite3_free(z_err as *mut ()) };
            z_err = core::ptr::null_mut();
        }
        z_q2 = unsafe { malloc((len + 100) as u64) } as *mut i8;
        if z_q2 == core::ptr::null_mut() { return rc; }
        unsafe {
            sqlite3_snprintf(len + 100, z_q2,
                c"%s ORDER BY rowid DESC".as_ptr() as *mut i8 as *const i8,
                z_query_1)
        };
        rc =
            unsafe {
                sqlite3_exec(unsafe { (*p).db }, z_q2 as *const i8,
                    Some(dump_callback), p as *mut (), &mut z_err)
            };
        if rc != 0 {
            unsafe {
                cli_printf(unsafe { (*p).out },
                    c"/****** ERROR: %s ******/\n".as_ptr() as *mut i8 as
                        *const i8, z_err)
            };
        } else { rc = 11; }
        unsafe { free(z_q2 as *mut ()) };
    }
    unsafe { sqlite3_free(z_err as *mut ()) };
    return rc;
}

